def test_options_whitespace_normalized() -> None:
    """Normalized whitespace mode collapses multiple spaces."""
    html = "<p>Text   with    extra   spaces.</p>"
    options = ConversionOptions(whitespace_mode="Normalized")

    result = convert(html, options)
    assert result.content  # noqa: S101
    assert result.content is not None  # noqa: S101
    assert "Text" in result.content  # noqa: S101
    assert result.content is not None  # noqa: S101
    assert "with" in result.content  # noqa: S101
    assert result.content is not None  # noqa: S101
    assert "extra" in result.content  # noqa: S101
    assert result.content is not None  # noqa: S101
    assert "spaces." in result.content  # noqa: S101


def test_options_whitespace_strict() -> None:
    """Strict whitespace mode preserves whitespace as-is."""
    html = "<p>Preserved   spacing.</p>"
    options = ConversionOptions(whitespace_mode="Strict")

    result = convert(html, options)
    assert result.content  # noqa: S101
    assert result.content is not None  # noqa: S101
    assert "Preserved" in result.content  # noqa: S101
    assert result.content is not None  # noqa: S101
    assert "spacing." in result.content  # noqa: S101


def test_options_wrap_disabled() -> None:
    """Wrap option disabled preserves long lines without breaking."""
    html = "<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>"
    options = ConversionOptions(wrap=False)

    result = convert(html, options)
    assert result.content is not None  # noqa: S101
    assert (
        "This is a long paragraph that should not be wrapped at all because wrapping is disabled."
        in result.content
    )  # noqa: S101


def test_options_wrap_enabled() -> None:
    """Wrap option enabled with custom width wraps long lines."""
    html = "<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>"
    options = ConversionOptions(wrap=True, wrap_width=40)

    result = convert(html, options)
    assert result.content  # noqa: S101
    assert result.content is not None  # noqa: S101
    assert "This is a long paragraph" in result.content  # noqa: S101
